12: absl::StatusOr<Http::FilterFactoryCb>
13: ExternalProcessingFilterConfig::createFilterFactoryFromProtoTyped(
14:     const envoy::extensions::filters::http::ext_proc::v3::ExternalProcessor& proto_config,
15:     const std::string& stats_prefix, DualInfo dual_info,
16:     Server::Configuration::ServerFactoryContext& context) {
17:   const uint32_t message_timeout_ms =
18:       PROTOBUF_GET_MS_OR_DEFAULT(proto_config, message_timeout, DefaultMessageTimeoutMs);
19:   const uint32_t max_message_timeout_ms =
20:       PROTOBUF_GET_MS_OR_DEFAULT(proto_config, max_message_timeout, DefaultMaxMessageTimeoutMs);
21:   const auto filter_config = std::make_shared<FilterConfig>(
22:       proto_config, std::chrono::milliseconds(message_timeout_ms), max_message_timeout_ms,
23:       dual_info.scope, stats_prefix, dual_info.is_upstream,
24:       Envoy::Extensions::Filters::Common::Expr::getBuilder(context), context);
25: 
26:   return [filter_config, grpc_service = proto_config.grpc_service(), &context,
27:           dual_info](Http::FilterChainFactoryCallbacks& callbacks) {
28:     auto client = std::make_unique<ExternalProcessorClientImpl>(
29:         context.clusterManager().grpcAsyncClientManager(), dual_info.scope);
30: 
31:     callbacks.addStreamFilter(Http::StreamFilterSharedPtr{
32:         std::make_shared<Filter>(filter_config, std::move(client), grpc_service)});
33:   };
34: }
