127: // Changes to headers are normally tested against the MutationRules supplied
128: // with configuration. When writing an immediate response message, however,
129: // we want to support a more liberal set of rules so that filters can create
130: // custom error messages, and we want to prevent the MutationRules in the
131: // configuration from making that impossible. This is a fixed, permissive
132: // set of rules for that purpose.
133: class ImmediateMutationChecker {
134: public:
135:   ImmediateMutationChecker(Regex::Engine& regex_engine) {
136:     envoy::config::common::mutation_rules::v3::HeaderMutationRules rules;
137:     rules.mutable_allow_all_routing()->set_value(true);
138:     rules.mutable_allow_envoy()->set_value(true);
139:     rule_checker_ = std::make_unique<Filters::Common::MutationRules::Checker>(rules, regex_engine);
140:   }
141: 
142:   const Filters::Common::MutationRules::Checker& checker() const { return *rule_checker_; }
143: 
144: private:
145:   std::unique_ptr<Filters::Common::MutationRules::Checker> rule_checker_;
146: };
